"use strict";parserFactory.register("titannovel.net",()=>new TitannovelParser);class TitannovelParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.querySelector("ul.list");return util.hyperlinksToChapterList(t)}findContent(e){return e.querySelector(".content")}extractTitleImpl(e){return e.querySelector(".meta h1 a")}extractAuthor(e){let t=e.querySelector(".meta span a");return t?.textContent??super.extractAuthor(e)}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,".jp-relatedposts"),super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector("h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".cover")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("#content-a")]}}